-- NOTE: REGULIS IDs continue from seed 020 (std_reg_149). These start at std_reg_150.

-- LA Rent Stabilization Ordinance
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_150', 'REGULIS', 'STATE_STATUTE', 'CA', 'Los Angeles Municipal Code Ch. XV, Art. 1 (Rent Stabilization Ordinance)', 'LAMC Ch. XV Art. 1 / RSO', 'Los Angeles Rent Stabilization Ordinance', 'Covers approximately 624,000 rental units built before October 1, 1978. Annual allowable increase set by LAHD (typically 3-8%). 12 just cause grounds for eviction. Owner move-in requires relocation assistance. Primary renovation evictions (Ellis Act) subject to extensive requirements. Mandatory registration with LAHD. No vacancy decontrol exemption from just cause.', '["Covers units built before October 1, 1978","Annual allowable increase set by LAHD — based on CPI","12 just cause grounds for eviction","Owner move-in: good faith intent, relocation payment required","Primary renovation: requires extensive notice and relocation","Ellis Act withdrawal: subject to local requirements plus state law","Mandatory registration with LA Housing Department","Relocation assistance: $8,650-$21,200+ depending on tenant category","RAP (Rent Adjustment Program) — petition for adjustments","No vacancy decontrol from just cause (Costa-Hawkins only decontrols rent)"]', '[{"section":"151.01-151.02","description":"Definitions and covered units"},{"section":"151.04","description":"Annual allowable rent increase"},{"section":"151.06","description":"Registration requirements"},{"section":"151.09","description":"12 just cause grounds for eviction"},{"section":"151.09(a)(8)","description":"Owner move-in eviction requirements"},{"section":"151.09(g)","description":"Relocation assistance amounts by category"},{"section":"151.10","description":"Rent adjustment — landlord and tenant petitions"}]', '["rent_increase_notice","eviction_notice","LAHD_registration","relocation_payment","OMI_declaration","rent_adjustment_petition","RAP_hearing"]', '["california-housing-tenant-audit"]', 'LA Housing Department (LAHD)', 1, 1, datetime('now'), datetime('now'));

-- San Jose Apartment Rent Ordinance
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_151', 'REGULIS', 'STATE_STATUTE', 'CA', 'San Jose Municipal Code Ch. 17.23 (Apartment Rent Ordinance — Measure V)', 'SJMC Ch. 17.23 / Measure V', 'San Jose Apartment Rent Ordinance — Measure V', 'Covers apartments (3+ units) built before September 7, 1979. Annual allowable increase of 5% or 8% of CPI (whichever is greater). Just cause required for eviction. Petition process for additional rent increases. Anti-retaliation protections. Tenant may petition for downward rent adjustment for decreased services or habitability issues.', '["Covers apartments of 3+ units built before September 7, 1979","Annual increase: 5% or 8% of CPI, whichever is greater","Just cause required for eviction","Landlord petition for increase above annual adjustment","Tenant petition for decrease based on reduced services","Voluntary vacancy decontrol under Costa-Hawkins","Anti-retaliation protections","Mandatory registration and annual fee","Relocation assistance for no-fault evictions"]', '[{"section":"17.23.200","description":"Covered units — apartments, 3+ units, pre-9/7/1979"},{"section":"17.23.310","description":"Annual allowable rent increase"},{"section":"17.23.460","description":"Just cause eviction requirements"},{"section":"17.23.500","description":"Petition process for additional increases"},{"section":"17.23.600","description":"Tenant petition for decrease"},{"section":"17.23.700","description":"Anti-retaliation provisions"}]', '["rent_increase_notice","eviction_notice","landlord_petition","tenant_petition","registration_filing","relocation_assistance"]', '["california-housing-tenant-audit"]', 'San Jose Rent Stabilization Program', 1, 1, datetime('now'), datetime('now'));

-- Richmond Fair Rent Ordinance
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_152', 'REGULIS', 'STATE_STATUTE', 'CA', 'Richmond Municipal Code Ch. 11.100 (Fair Rent, Just Cause for Eviction, and Homeowner Protection Ordinance)', 'RMC Ch. 11.100', 'Richmond Fair Rent, Just Cause for Eviction, and Homeowner Protection', 'Voter-approved ordinance (Measure L, 2016) covering most rental units. Annual CPI-based increase (max 100% of CPI). Just cause required for all evictions. Elected Rent Board. Broad coverage including single-family homes (unlike many jurisdictions). Relocation assistance for no-fault evictions. Banking of rent increases permitted in limited circumstances.', '["Covers most rental units including single-family homes","Annual increase: 100% of CPI (no additional percentage added)","Just cause required for all evictions","Elected 5-member Rent Board","Relocation assistance for no-fault evictions","Registration required for all covered units","Tenant petitions for rent decrease available","Anti-retaliation and anti-harassment protections","Banking of increases in limited circumstances"]', '[{"section":"11.100.030","description":"Covered units — broad, includes single-family"},{"section":"11.100.040","description":"Annual general adjustment — CPI-based"},{"section":"11.100.050","description":"Just cause for eviction requirements"},{"section":"11.100.060","description":"Petition process — landlord and tenant"},{"section":"11.100.070","description":"Relocation assistance for no-fault evictions"},{"section":"11.100.080","description":"Rent Board — elected, 5 members"}]', '["rent_increase_notice","eviction_notice","rent_board_petition","registration","relocation_payment","hearing_decision"]', '["california-housing-tenant-audit"]', 'Richmond Rent Board', 1, 1, datetime('now'), datetime('now'));

-- Mountain View CSFRA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_153', 'REGULIS', 'STATE_STATUTE', 'CA', 'Mountain View City Code Ch. 36, Art. XVII (CSFRA — Measure V, 2016)', 'CSFRA / MV Measure V', 'Mountain View Community Stabilization and Fair Rent Act', 'Voter-approved (Measure V, 2016). Covers most rental units built before February 1, 1995. Elected 5-member Rental Housing Committee sets annual adjustment. Just cause for eviction. Allows landlords to petition for fair return on investment. Tenant protections include anti-harassment, anti-retaliation, and relocation assistance.', '["Covers units built before February 1, 1995","Elected Rental Housing Committee sets annual adjustment","Just cause required for eviction","Landlord fair return petition available","Tenant petition for excessive rent increase","Anti-harassment and anti-retaliation protections","Relocation assistance for no-fault evictions","Registration required for all covered units"]', '[{"section":"1700","description":"Findings and purpose"},{"section":"1702","description":"Definitions and covered units"},{"section":"1706","description":"Annual general adjustment"},{"section":"1710","description":"Just cause for eviction — enumerated grounds"},{"section":"1712","description":"Petition process for adjustments"},{"section":"1714","description":"Relocation assistance requirements"}]', '["rent_increase_notice","eviction_notice","RHC_petition","registration","relocation_payment","hearing_decision"]', '["california-housing-tenant-audit"]', 'Mountain View Rental Housing Committee', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- REGULIS — Labor Law Expansion
